protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(b =>
    {
        b.ToContainer("Products");

        // EF Core 9: default discriminator property renamed from "Discriminator" to "$type".
        // Preserve old name so existing documents and direct SQL queries remain compatible.
        b.HasDiscriminator<string>("Discriminator");

        // EF Core 9: id values no longer include the discriminator prefix.
        // Preserve old "Product|123" format so existing 500K documents stay readable.
        b.HasRootDiscriminatorInJsonId(true);
    });
    // HasIndex removed — Cosmos DB provider now throws at startup.
    // Manage indexing via the container's indexing policy in Azure Portal / Bicep / Terraform.
}

